import{_ as a,o as e,c as l,a2 as r}from"./chunks/framework.BQ1gajhD.js";const x=JSON.parse('{"title":"居庸关","description":"","frontmatter":{},"headers":[],"relativePath":"landmarks/juyongguan.md","filePath":"landmarks/juyongguan.md","lastUpdated":1784712887000}'),n={name:"landmarks/juyongguan.md"};function o(i,t,d,s,h,g){return e(),l("div",null,[...t[0]||(t[0]=[r('<h1 id="居庸关" tabindex="-1">居庸关 <a class="header-anchor" href="#居庸关" aria-label="Permalink to &quot;居庸关&quot;">​</a></h1><p><img src="https://images.unsplash.com/photo-1548013146-72479768bada?w=1200" alt="居庸关"></p><blockquote><p>&quot;天下第一雄关，云台石刻耀古今。&quot;</p></blockquote><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>居庸关是万里长城的重要关隘，位于北京市昌平区，距北京城区约50公里。居庸关地势险要，自古为兵家必争之地，被誉为&quot;天下第一雄关&quot;。关城内的云台建于元代，是世界文化遗产的重要组成部分。</p><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>开放时间</strong></td><td style="text-align:left;">8:30-16:30</td></tr><tr><td style="text-align:left;"><strong>门票价格</strong></td><td style="text-align:left;">旺季45元，淡季40元</td></tr><tr><td style="text-align:left;"><strong>建议游玩</strong></td><td style="text-align:left;">2-3小时</td></tr><tr><td style="text-align:left;"><strong>最佳季节</strong></td><td style="text-align:left;">春秋两季</td></tr><tr><td style="text-align:left;"><strong>交通方式</strong></td><td style="text-align:left;">地铁昌平线转公交或自驾</td></tr><tr><td style="text-align:left;"><strong>地址</strong></td><td style="text-align:left;">北京市昌平区南口镇居庸关村</td></tr></tbody></table><h2 id="历史沿革" tabindex="-1">历史沿革 <a class="header-anchor" href="#历史沿革" aria-label="Permalink to &quot;历史沿革&quot;">​</a></h2><h3 id="始建" tabindex="-1">始建 <a class="header-anchor" href="#始建" aria-label="Permalink to &quot;始建&quot;">​</a></h3><p>居庸关始建于秦代，相传秦始皇修长城时，将强征来的民夫士卒徙居于此，取&quot;徙居庸徒&quot;之意，故名居庸关。</p><h3 id="历代修缮" tabindex="-1">历代修缮 <a class="header-anchor" href="#历代修缮" aria-label="Permalink to &quot;历代修缮&quot;">​</a></h3><ul><li><strong>汉代</strong>：设置居庸县，为军事重镇</li><li><strong>北魏</strong>：在关城修建永明寺</li><li><strong>元代</strong>：修建云台，这是现存的主要遗迹</li><li><strong>明代</strong>：大规模重修，形成今日规模</li></ul><h3 id="历史地位" tabindex="-1">历史地位 <a class="header-anchor" href="#历史地位" aria-label="Permalink to &quot;历史地位&quot;">​</a></h3><p>居庸关是北京西北的重要屏障，历史上多次成为军事要塞。成吉思汗、李自成等都曾攻打过居庸关。</p><h2 id="建筑特色" tabindex="-1">建筑特色 <a class="header-anchor" href="#建筑特色" aria-label="Permalink to &quot;建筑特色&quot;">​</a></h2><h3 id="关城布局" tabindex="-1">关城布局 <a class="header-anchor" href="#关城布局" aria-label="Permalink to &quot;关城布局&quot;">​</a></h3><p>居庸关关城呈圆周封闭形，周长4142米。关城设有南北两座城门，南门名为&quot;南口&quot;，北门名为&quot;北口&quot;。</p><h3 id="云台" tabindex="-1">云台 <a class="header-anchor" href="#云台" aria-label="Permalink to &quot;云台&quot;">​</a></h3><p>云台是居庸关最著名的建筑，建于元代至正五年（1345年），原为过街塔的基座。过街塔已毁，仅存云台。</p><h4 id="云台石刻" tabindex="-1">云台石刻 <a class="header-anchor" href="#云台石刻" aria-label="Permalink to &quot;云台石刻&quot;">​</a></h4><p>云台内外的石刻艺术是居庸关的精华所在：</p><ul><li><strong>四大天王像</strong>：云台南北券洞内雕刻四大天王，高达3米，神态各异</li><li><strong>梵文经文</strong>：券洞两壁刻有梵文、藏文、八思巴文、维吾尔文、汉文、西夏文六种文字的佛经</li><li><strong>浮雕</strong>：券顶雕刻大鹏金翅鸟、鲸鱼、龙子等精美图案</li></ul><h4 id="历史价值" tabindex="-1">历史价值 <a class="header-anchor" href="#历史价值" aria-label="Permalink to &quot;历史价值&quot;">​</a></h4><p>云台石刻是元代雕刻艺术的杰作，具有极高的艺术价值和历史价值。六种文字的佛经刻石，是研究古代文字和佛教的重要实物资料。</p><h3 id="居庸叠翠" tabindex="-1">居庸叠翠 <a class="header-anchor" href="#居庸叠翠" aria-label="Permalink to &quot;居庸叠翠&quot;">​</a></h3><p>居庸关两侧山峦叠嶂，翠峰重峦，是&quot;燕京八景&quot;之一的&quot;居庸叠翠&quot;。乾隆年间，乾隆皇帝曾在此题刻&quot;居庸叠翠&quot;四字。</p><h2 id="游览区域" tabindex="-1">游览区域 <a class="header-anchor" href="#游览区域" aria-label="Permalink to &quot;游览区域&quot;">​</a></h2><h3 id="云台-1" tabindex="-1">云台 <a class="header-anchor" href="#云台-1" aria-label="Permalink to &quot;云台&quot;">​</a></h3><p>云台是居庸关的核心景点，也是必看之处。穿过云台，仰望精美的石刻，感受元代艺术的魅力。</p><h3 id="关城" tabindex="-1">关城 <a class="header-anchor" href="#关城" aria-label="Permalink to &quot;关城&quot;">​</a></h3><p>登上关城，可以俯瞰居庸关的全貌，远眺连绵的山峦和蜿蜒的长城。</p><h3 id="博物馆" tabindex="-1">博物馆 <a class="header-anchor" href="#博物馆" aria-label="Permalink to &quot;博物馆&quot;">​</a></h3><p>居庸关内设有长城博物馆，展示居庸关的历史和长城文化。</p><h2 id="居庸关与八达岭" tabindex="-1">居庸关与八达岭 <a class="header-anchor" href="#居庸关与八达岭" aria-label="Permalink to &quot;居庸关与八达岭&quot;">​</a></h2><p>居庸关与八达岭相邻，但各有特色：</p><table tabindex="0"><thead><tr><th style="text-align:left;">对比项</th><th style="text-align:left;">居庸关</th><th style="text-align:left;">八达岭</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>特色</strong></td><td style="text-align:left;">云台石刻、关城</td><td style="text-align:left;">城墙、敌楼</td></tr><tr><td style="text-align:left;"><strong>历史</strong></td><td style="text-align:left;">元代云台</td><td style="text-align:left;">明代长城</td></tr><tr><td style="text-align:left;"><strong>人流</strong></td><td style="text-align:left;">较少</td><td style="text-align:left;">较多</td></tr><tr><td style="text-align:left;"><strong>难度</strong></td><td style="text-align:left;">较轻松</td><td style="text-align:left;">较累</td></tr><tr><td style="text-align:left;"><strong>推荐</strong></td><td style="text-align:left;">文化历史</td><td style="text-align:left;">登城体验</td></tr></tbody></table><h2 id="游览攻略" tabindex="-1">游览攻略 <a class="header-anchor" href="#游览攻略" aria-label="Permalink to &quot;游览攻略&quot;">​</a></h2><h3 id="推荐路线" tabindex="-1">推荐路线 <a class="header-anchor" href="#推荐路线" aria-label="Permalink to &quot;推荐路线&quot;">​</a></h3><p><strong>经典路线（约2-3小时）</strong>：</p><p>南门 → 云台（重点游览） → 关城 → 博物馆 → 北门</p><p><strong>结合八达岭路线（约1天）</strong>：</p><p>上午八达岭 → 下午居庸关 → 返程</p><h3 id="交通方式" tabindex="-1">交通方式 <a class="header-anchor" href="#交通方式" aria-label="Permalink to &quot;交通方式&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">方式</th><th style="text-align:left;">路线</th><th style="text-align:center;">时间</th></tr></thead><tbody><tr><td style="text-align:left;">公交</td><td style="text-align:left;">地铁昌平线昌平站 → 昌20路 → 居庸关</td><td style="text-align:center;">约2小时</td></tr><tr><td style="text-align:left;">自驾</td><td style="text-align:left;">京藏高速 → 居庸关出口</td><td style="text-align:center;">约1小时</td></tr><tr><td style="text-align:left;">包车</td><td style="text-align:left;">市区往返</td><td style="text-align:center;">约1小时</td></tr></tbody></table><h3 id="实用贴士" tabindex="-1">实用贴士 <a class="header-anchor" href="#实用贴士" aria-label="Permalink to &quot;实用贴士&quot;">​</a></h3><ol><li><strong>云台重点</strong>：云台是精华，务必仔细观赏</li><li><strong>石刻保护</strong>：石刻珍贵，请勿触摸</li><li><strong>光线选择</strong>：下午光线较好，适合拍摄</li><li><strong>结合游览</strong>：可与八达岭安排在同一天游览</li><li><strong>游客较少</strong>：比八达岭人少，体验更好</li></ol><h2 id="文化价值" tabindex="-1">文化价值 <a class="header-anchor" href="#文化价值" aria-label="Permalink to &quot;文化价值&quot;">​</a></h2><p>居庸关云台是国家级重点文物保护单位，1961年被列入第一批全国重点文物保护单位名单。</p><p>云台石刻是元代雕刻艺术的瑰宝，具有极高的历史、艺术和科学价值。六种文字的佛经刻石，是研究古代各民族文化交流的重要资料。</p><hr><p><strong>📍 地址</strong>：北京市昌平区南口镇居庸关村 <strong>📞 电话</strong>：010-69771665</p>',51)])])}const f=a(n,[["render",o]]);export{x as __pageData,f as default};
